// ── Example 6 — RolesPlate, both themes: the eight roles table above, drawn instead of merely
//    tabulated. Mechanism (A)'s second consumer (DESIGN11) — a `Palette`, instantiated twice,
//    the same edge substitution `LightCardPalette`/`DarkCardPalette` already stands on, written
//    to `roles-plate.svg`/`roles-plate~dark.svg`, DocC's own native asset-swap for a grid tile.
//    Associated-type names carry a `Color` suffix so a palette's OWN requirement never collides
//    with the global role atom of the (almost) same name it is bound to. ──

public protocol RolesPalette {
    associatedtype CardColor: Structure
    associatedtype TrackColor: Structure
    associatedtype PrimaryColor: Structure
    associatedtype SecondaryColor: Structure
    associatedtype AccentColor: Structure
    associatedtype ActionColor: Structure
    associatedtype LineColor: Structure
    associatedtype OnAccentColor: Structure
}
